1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	interface QuoteResult {
17	  premium: number;
18	}
19	
20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PRICE = 60;
22	
23	const quotePremium = (items: Array<{ type: string }>): number => {
24	  const typeCounts: Record<string, number> = {};
25	  for (const item of items) {
26	    typeCounts[item.type] = (typeCounts[item.type] ?? 0) + 1;
27	  }
28	  let total = 0;
29	  for (const [type, count] of Object.entries(typeCounts)) {
30	    if (count === COMPONENT_BLOCK_SIZE) {
31	      total += COMPONENT_BLOCK_PRICE;
32	    } else {
33	      total += count * (BASE_PREMIUMS[type] ?? 0);
34	    }
35	  }
36	  return total + PROCESSING_FEE;
37	};
38	
39	export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<{ type: string }> }>): Array<QuoteResult> =>
40	  steps.map((step) => ({
41	    premium: quotePremium(step.items),
42	  }));
